#include <bits/stdc++.h>
using namespace std;

const int N=105;

int n;
double a[N][N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n+1;j++)
            scanf("%lf",&a[i][j]);
    double num;
    for(int i=1;i<=n;i++){
        int r=i;
        for(int j=i+1;j<=n;j++)
            if(fabs(a[j][i])>fabs(a[r][i]))
                r=j;
        if(fabs(a[r][i])<=1e-6){
            puts("No Solution");
            return 0;
        }
        for(int j=1;j<=n+1;j++)
            swap(a[i][j],a[r][j]);
        for(int j=i+1;j<=n;j++){
            num=a[j][i]/a[i][i];
            for(int k=i;k<=n+1;k++)
                a[j][k]-=a[i][k]*num;
        }
        num=a[i][i];
        for(int j=i;j<=n+1;j++)
            a[i][j]/=num;
    }
    for(int i=n;i;i--){
        if(a[i][i]==0){
            puts("No Solution");
            return 0;
        }
        for(int j=i-1;j;j--){
            num=a[j][i];
            a[j][n+1]-=num*a[i][n+1];
            a[j][i]=0;
        }
    }
    for(int i=1;i<=n;i++)
        printf("%.2lf\n",a[i][n+1]);
    return 0;
}
